function generateMonthlyEvents(e) {
    const i = [];
    for (let s = 0; s < 12; s++) {
        const o = String(s + 1).padStart(2, "0"),
            a = e + "-" + o;
        i.push({
            date: a + "-03",
            type: "tufe",
            title: "[TR] TUFE (Enflasyon) Verisi",
            impact: "high"
        }), i.push({
            date: a + "-03",
            type: "ufe",
            title: "[TR] UFE (Uretici Fiyatlari)",
            impact: "medium"
        }), (s === 2 || s === 5 || s === 8 || s === 11) && i.push({
            date: a + "-10",
            type: "gsyih",
            title: "[TR] GSYIH Buyume Verisi",
            impact: "high"
        }), i.push({
            date: a + "-10",
            type: "istihdam",
            title: "[TR] Istihdam / Issizlik Verisi",
            impact: "medium"
        }), i.push({
            date: a + "-28",
            type: "disticaret",
            title: "[TR] Dis Ticaret Dengesi",
            impact: "medium"
        }), i.push({
            date: a + "-15",
            type: "sanayi",
            title: "[TR] Sanayi Uretim Endeksi",
            impact: "low"
        }), i.push({
            date: a + "-14",
            type: "disticaret",
            title: "[TR] Cari Islemler Dengesi",
            impact: "medium"
        }), i.push({
            date: a + "-15",
            type: "other",
            title: "[TR] Merkezi Yonetim Butce Dengesi",
            impact: "low"
        }), i.push({
            date: a + "-25",
            type: "other",
            title: "[TR] Tuketici Guven Endeksi",
            impact: "low"
        }), i.push({
            date: a + "-01",
            type: "pmi",
            title: "[TR] Istanbul Sanayi Odasi PMI",
            impact: "medium"
        })
    }
    return i
}
const ALL_EVENTS = [...TCMB_MEETINGS, ...generateMonthlyEvents("2025"), ...generateMonthlyEvents("2026"), ...generateMonthlyEvents("2027")];

function getUpcomingEvents(e = 30) {
    const i = new Date,
        s = new Date(i.getTime() + e * 864e5);
    return ALL_EVENTS.filter(o => {
        const a = new Date(o.date);
        return a >= i && a <= s
    }).sort((o, a) => new Date(o.date) - new Date(a.date))
}
